import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  FileText, Zap, Plus, Star, Clock, TrendingUp,
  ArrowRight, BookOpen, Briefcase, Download,
} from 'lucide-react';
import { format } from 'date-fns';
import toast from 'react-hot-toast';
import { useAuth } from '../store/AuthContext';
import { documentsAPI } from '../utils/api';

const StatCard = ({ icon: Icon, label, value, sub, color = 'var(--accent)' }) => (
  <div className="card" style={{ display: 'flex', alignItems: 'flex-start', gap: '16px' }}>
    <div style={{
      width: '44px', height: '44px', flexShrink: 0,
      background: `${color}20`,
      borderRadius: '12px',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
    }}>
      <Icon size={20} color={color} />
    </div>
    <div>
      <p style={{ fontSize: '13px', color: 'var(--text-muted)', marginBottom: '4px' }}>{label}</p>
      <p style={{ fontSize: '28px', fontWeight: '800', letterSpacing: '-0.03em', lineHeight: 1 }}>{value}</p>
      {sub && <p style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '4px' }}>{sub}</p>}
    </div>
  </div>
);

const DashboardPage = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [recentDocs, setRecentDocs] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [docsRes, statsRes] = await Promise.all([
          documentsAPI.getAll({ limit: 5 }),
          documentsAPI.getStats(),
        ]);
        setRecentDocs(docsRes.data.documents);
        setStats(statsRes.data);
      } catch (err) {
        toast.error('Failed to load dashboard data.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const handleExportPDF = async (docId, title) => {
    try {
      const res = await documentsAPI.exportPDF(docId);
      const url = window.URL.createObjectURL(new Blob([res.data]));
      const a = document.createElement('a');
      a.href = url;
      a.download = `${title.replace(/[^a-z0-9]/gi, '_')}.pdf`;
      a.click();
      window.URL.revokeObjectURL(url);
      toast.success('PDF downloaded!');
    } catch {
      toast.error('Export failed. Please try again.');
    }
  };

  const generationPct = Math.min(
    100,
    ((user?.generationsUsed || 0) / (user?.generationsLimit || 10)) * 100
  );

  const statsCards = [
    {
      icon: FileText,
      label: 'Total Documents',
      value: stats?.total ?? '—',
      color: 'var(--accent)',
    },
    {
      icon: Briefcase,
      label: 'Resumes',
      value: stats?.stats?.find(s => s._id === 'resume')?.count ?? 0,
      color: 'var(--accent-light)',
    },
    {
      icon: BookOpen,
      label: 'Blog Posts',
      value: stats?.stats?.find(s => s._id === 'blog')?.count ?? 0,
      color: 'var(--accent-green)',
    },
    {
      icon: Star,
      label: 'Favourites',
      value: stats?.favorites ?? 0,
      color: 'var(--accent-yellow)',
    },
  ];

  return (
    <div className="container" style={{ paddingTop: '40px', paddingBottom: '60px' }}>
      {/* Greeting */}
      <div className="fade-in" style={{ marginBottom: '36px' }}>
        <h1 style={{ fontSize: '32px', letterSpacing: '-0.03em', marginBottom: '6px' }}>
          Good {new Date().getHours() < 12 ? 'morning' : new Date().getHours() < 17 ? 'afternoon' : 'evening'},{' '}
          <span style={{ color: 'var(--accent)' }}>{user?.name?.split(' ')[0]}</span> 👋
        </h1>
        <p style={{ color: 'var(--text-secondary)', fontSize: '15px' }}>
          {format(new Date(), 'EEEE, MMMM d, yyyy')}
        </p>
      </div>

      {/* Stats Grid */}
      <div className="fade-in" style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
        gap: '16px',
        marginBottom: '36px',
      }}>
        {statsCards.map((s) => (
          <StatCard key={s.label} {...s} />
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 340px', gap: '24px', alignItems: 'start' }}
        className="dashboard-grid">
        {/* Left: Recent + Quick Actions */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
          {/* Quick Actions */}
          <div className="card fade-in fade-in-delay-1">
            <h2 style={{ fontSize: '17px', marginBottom: '16px' }}>Quick Generate</h2>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
              <button
                className="btn"
                onClick={() => navigate('/generate/resume')}
                style={{
                  background: 'rgba(108, 99, 255, 0.1)',
                  border: '1px solid var(--border-strong)',
                  color: 'var(--text-primary)',
                  padding: '20px',
                  flexDirection: 'column',
                  alignItems: 'flex-start',
                  gap: '10px',
                  height: 'auto',
                  borderRadius: 'var(--radius)',
                }}
              >
                <div style={{
                  width: '40px', height: '40px',
                  background: 'rgba(108, 99, 255, 0.2)',
                  borderRadius: '10px',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}>
                  <Briefcase size={18} color="var(--accent)" />
                </div>
                <div style={{ textAlign: 'left' }}>
                  <p style={{ fontWeight: '700', fontSize: '15px' }}>Resume</p>
                  <p style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '2px' }}>
                    AI-crafted resume
                  </p>
                </div>
              </button>

              <button
                className="btn"
                onClick={() => navigate('/generate/blog')}
                style={{
                  background: 'rgba(67, 217, 162, 0.08)',
                  border: '1px solid rgba(67, 217, 162, 0.2)',
                  color: 'var(--text-primary)',
                  padding: '20px',
                  flexDirection: 'column',
                  alignItems: 'flex-start',
                  gap: '10px',
                  height: 'auto',
                  borderRadius: 'var(--radius)',
                }}
              >
                <div style={{
                  width: '40px', height: '40px',
                  background: 'rgba(67, 217, 162, 0.15)',
                  borderRadius: '10px',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}>
                  <BookOpen size={18} color="var(--accent-green)" />
                </div>
                <div style={{ textAlign: 'left' }}>
                  <p style={{ fontWeight: '700', fontSize: '15px' }}>Blog Post</p>
                  <p style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '2px' }}>
                    SEO-optimized article
                  </p>
                </div>
              </button>
            </div>
          </div>

          {/* Recent Documents */}
          <div className="card fade-in fade-in-delay-2">
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h2 style={{ fontSize: '17px' }}>Recent Documents</h2>
              <Link to="/documents" className="btn btn-ghost" style={{ fontSize: '13px', color: 'var(--accent-light)' }}>
                View all <ArrowRight size={14} />
              </Link>
            </div>

            {loading ? (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {[1, 2, 3].map(i => (
                  <div key={i} style={{
                    height: '56px',
                    background: 'var(--bg-input)',
                    borderRadius: 'var(--radius-sm)',
                    animation: 'pulse 1.5s ease infinite',
                  }} />
                ))}
              </div>
            ) : recentDocs.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '40px 20px' }}>
                <FileText size={32} color="var(--text-muted)" style={{ margin: '0 auto 12px' }} />
                <p style={{ color: 'var(--text-muted)', fontSize: '14px' }}>
                  No documents yet. Generate your first one!
                </p>
                <Link to="/generate" className="btn btn-primary" style={{ marginTop: '16px' }}>
                  <Zap size={16} /> Generate Now
                </Link>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                {recentDocs.map((doc) => (
                  <div
                    key={doc._id}
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: '12px',
                      padding: '12px',
                      borderRadius: 'var(--radius-sm)',
                      background: 'var(--bg-input)',
                      border: '1px solid transparent',
                      transition: 'all var(--transition)',
                      cursor: 'pointer',
                    }}
                    onMouseEnter={e => {
                      e.currentTarget.style.borderColor = 'var(--border)';
                      e.currentTarget.style.background = 'var(--bg-card-hover)';
                    }}
                    onMouseLeave={e => {
                      e.currentTarget.style.borderColor = 'transparent';
                      e.currentTarget.style.background = 'var(--bg-input)';
                    }}
                    onClick={() => navigate(`/editor/${doc._id}`)}
                  >
                    <div style={{
                      width: '36px', height: '36px', flexShrink: 0,
                      background: doc.type === 'resume' ? 'rgba(108,99,255,0.15)' : 'rgba(67,217,162,0.12)',
                      borderRadius: '8px',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                    }}>
                      {doc.type === 'resume'
                        ? <Briefcase size={16} color="var(--accent)" />
                        : <BookOpen size={16} color="var(--accent-green)" />
                      }
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <p style={{
                        fontWeight: '600', fontSize: '14px',
                        overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                      }}>{doc.title}</p>
                      <p style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '2px' }}>
                        <Clock size={10} style={{ display: 'inline', marginRight: '4px' }} />
                        {format(new Date(doc.updatedAt), 'MMM d, yyyy')}
                      </p>
                    </div>
                    <span className={`badge badge-${doc.type}`}>{doc.type}</span>
                    <button
                      className="btn btn-ghost"
                      style={{ padding: '6px', flexShrink: 0 }}
                      onClick={(e) => { e.stopPropagation(); handleExportPDF(doc._id, doc.title); }}
                      title="Export PDF"
                    >
                      <Download size={14} />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Right: Usage + Tips */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          {/* Usage Card */}
          <div className="card fade-in fade-in-delay-1">
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px' }}>
              <h3 style={{ fontSize: '15px' }}>AI Usage</h3>
              <span className={`badge badge-${user?.plan}`}>{user?.plan}</span>
            </div>
            <div style={{ marginBottom: '12px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                <span style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>Generations</span>
                <span style={{ fontSize: '13px', fontWeight: '700' }}>
                  {user?.generationsUsed || 0} / {user?.generationsLimit || 10}
                </span>
              </div>
              <div style={{ height: '8px', background: 'var(--bg-input)', borderRadius: '4px', overflow: 'hidden' }}>
                <div style={{
                  height: '100%',
                  width: `${generationPct}%`,
                  background: generationPct > 80
                    ? 'var(--accent-secondary)'
                    : generationPct > 50
                      ? 'var(--accent-yellow)'
                      : 'var(--accent)',
                  borderRadius: '4px',
                  transition: 'width 0.6s ease',
                }} />
              </div>
              <p style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '6px' }}>
                {user?.generationsLimit - user?.generationsUsed} generations remaining
              </p>
            </div>
            {generationPct > 70 && (
              <div style={{
                background: 'rgba(246, 201, 14, 0.1)',
                border: '1px solid rgba(246, 201, 14, 0.25)',
                borderRadius: 'var(--radius-sm)',
                padding: '10px 12px',
                fontSize: '12px',
                color: 'var(--accent-yellow)',
              }}>
                ⚡ Running low — consider upgrading to Pro for 100 generations/month.
              </div>
            )}
          </div>

          {/* Tips Card */}
          <div className="card fade-in fade-in-delay-2">
            <h3 style={{ fontSize: '15px', marginBottom: '14px' }}>💡 Pro Tips</h3>
            <ul style={{ listStyle: 'none', display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {[
                'Be specific in your prompts for better results',
                'Use the editor to personalize AI output',
                'Export to PDF for professional sharing',
                'Star important docs to find them quickly',
              ].map((tip) => (
                <li key={tip} style={{
                  fontSize: '13px',
                  color: 'var(--text-secondary)',
                  paddingLeft: '16px',
                  position: 'relative',
                  lineHeight: '1.5',
                }}>
                  <span style={{ position: 'absolute', left: 0, color: 'var(--accent)' }}>›</span>
                  {tip}
                </li>
              ))}
            </ul>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
        @media (max-width: 900px) {
          .dashboard-grid {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </div>
  );
};

export default DashboardPage;
